/* stellar-sextant precision-instrument overrides */

/* ── page background ─────────────────────────────────────────── */
body.theme-stellar-sextant {
  background-color: var(--wp--preset--color--base);
  color: var(--wp--preset--color--secondary);
}

/* ── hero overlay depth ──────────────────────────────────────── */
body.theme-stellar-sextant .wp-block-cover__background,
body.theme-stellar-sextant .wp-block-cover .has-background-dim {
  opacity: 0.55;
  background-color: var(--wp--preset--color--base);
}

/* ── headings ─────────────────────────────────────────────────── */
body.theme-stellar-sextant h1,
body.theme-stellar-sextant h2,
body.theme-stellar-sextant h3,
body.theme-stellar-sextant h4,
body.theme-stellar-sextant h5,
body.theme-stellar-sextant h6 {
  color: var(--wp--preset--color--contrast);
}

/* section/category labels — uppercase tracked wide in tertiary */
body.theme-stellar-sextant .wp-block-query-title,
body.theme-stellar-sextant .section-label,
body.theme-stellar-sextant .wp-block-heading.is-style-section-label {
  color: var(--wp--preset--color--tertiary);
  text-transform: uppercase;
  letter-spacing: 0.15em;
  font-weight: 700;
}

/* ── body / secondary text ────────────────────────────────────── */
body.theme-stellar-sextant p,
body.theme-stellar-sextant li,
body.theme-stellar-sextant label,
body.theme-stellar-sextant .wc-block-components-product-price {
  color: var(--wp--preset--color--secondary);
}

/* muted metadata */
body.theme-stellar-sextant .wc-block-components-product-metadata,
body.theme-stellar-sextant .wp-block-post-date,
body.theme-stellar-sextant .wp-block-post-terms,
body.theme-stellar-sextant small,
body.theme-stellar-sextant .entry-meta {
  color: var(--wp--preset--color--tertiary);
}

/* ── product cards ────────────────────────────────────────────── */
body.theme-stellar-sextant .wc-block-grid__product,
body.theme-stellar-sextant .wp-block-woocommerce-product-template > li,
body.theme-stellar-sextant .wc-block-product-template > li {
  background-color: var(--wp--preset--color--surface);
  border: 1px solid var(--wp--preset--color--border);
  border-radius: 0;
  box-shadow: none;
}

/* ── editorial column ─────────────────────────────────────────── */
body.theme-stellar-sextant .editorial-column,
body.theme-stellar-sextant .shop-story {
  max-width: 640px;
  margin-inline: auto;
  padding-block: var(--wp--preset--spacing--lg) var(--wp--preset--spacing--xl);
}

/* ── section dividers ─────────────────────────────────────────── */
body.theme-stellar-sextant hr,
body.theme-stellar-sextant .wp-block-separator {
  border: none;
  border-top: 1px solid var(--wp--preset--color--muted);
  background: none;
  box-shadow: none;
  height: 1px;
}

/* ── CTA / primary buttons ────────────────────────────────────── */
body.theme-stellar-sextant .wp-block-button__link,
body.theme-stellar-sextant .wc-block-components-button,
body.theme-stellar-sextant .wc-block-cart__submit-container .wc-block-components-checkout-place-order-button,
body.theme-stellar-sextant .wc-block-cart__submit-container a.wc-block-cart__submit-button,
body.theme-stellar-sextant .wc-block-components-checkout-place-order-button,
body.theme-stellar-sextant .wo-empty__cta--primary {
  background-color: var(--wp--preset--color--accent);
  color: var(--wp--preset--color--base);
  border: none;
  border-radius: 0;
  box-shadow: none;
  transition: background-color 0.18s ease;
}

body.theme-stellar-sextant .wp-block-button__link:hover,
body.theme-stellar-sextant .wp-block-button__link:focus,
body.theme-stellar-sextant .wc-block-components-button:hover,
body.theme-stellar-sextant .wc-block-components-button:focus,
body.theme-stellar-sextant .wc-block-cart__submit-container .wc-block-components-checkout-place-order-button:hover,
body.theme-stellar-sextant .wc-block-cart__submit-container a.wc-block-cart__submit-button:hover,
body.theme-stellar-sextant .wc-block-components-checkout-place-order-button:hover,
body.theme-stellar-sextant .wo-empty__cta--primary:hover {
  background-color: var(--wp--preset--color--primary-hover);
  color: var(--wp--preset--color--base);
}

/* ── accent rule lines (decorative) ───────────────────────────── */
body.theme-stellar-sextant .accent-rule {
  border-top: 1px solid var(--wp--preset--color--accent);
}

/* ── footer three-column layout ───────────────────────────────── */
body.theme-stellar-sextant footer.wp-block-group,
body.theme-stellar-sextant .wp-block-template-part[class*="footer"] {
  background-color: var(--wp--preset--color--subtle);
}

body.theme-stellar-sextant .selvedge-footer__col-heading,
body.theme-stellar-sextant .footer-col-heading {
  color: var(--wp--preset--color--tertiary);
  text-transform: uppercase;
  letter-spacing: 0.15em;
  font-weight: 700;
}

body.theme-stellar-sextant .selvedge-footer__col + .selvedge-footer__col,
body.theme-stellar-sextant .footer-col + .footer-col {
  border-left: 1px solid var(--wp--preset--color--border);
}

/* ── surface backgrounds (cards, panels) ──────────────────────── */
body.theme-stellar-sextant .wp-block-group.has-surface-background-color,
body.theme-stellar-sextant .wc-block-mini-cart__drawer,
body.theme-stellar-sextant .wc-block-components-sidebar {
  background-color: var(--wp--preset--color--surface);
  box-shadow: none;
}

/* ── form inputs: match dark palette ─────────────────────────── */
body.theme-stellar-sextant input[type="text"],
body.theme-stellar-sextant input[type="email"],
body.theme-stellar-sextant input[type="password"],
body.theme-stellar-sextant input[type="search"],
body.theme-stellar-sextant input[type="number"],
body.theme-stellar-sextant select,
body.theme-stellar-sextant textarea {
  background-color: var(--wp--preset--color--subtle);
  color: var(--wp--preset--color--contrast);
  border: 1px solid var(--wp--preset--color--border);
  border-radius: 0;
  box-shadow: none;
}

body.theme-stellar-sextant input[type="text"]:focus,
body.theme-stellar-sextant input[type="email"]:focus,
body.theme-stellar-sextant input[type="password"]:focus,
body.theme-stellar-sextant input[type="search"]:focus,
body.theme-stellar-sextant input[type="number"]:focus,
body.theme-stellar-sextant select:focus,
body.theme-stellar-sextant textarea:focus {
  border-color: var(--wp--preset--color--accent);
  outline: none;
}

/* ── required field marker ────────────────────────────────────── */
body.theme-stellar-sextant .required,
body.theme-stellar-sextant abbr[title="required"] {
  color: var(--wp--preset--color--accent);
  text-decoration: none;
}
body.theme-stellar-sextant .required::after,
body.theme-stellar-sextant abbr[title="required"]::after {
  content: " ·";
}

/* ── navigation links ─────────────────────────────────────────── */
body.theme-stellar-sextant .wp-block-navigation a {
  color: var(--wp--preset--color--secondary);
}

body.theme-stellar-sextant .wp-block-navigation a:hover,
body.theme-stellar-sextant .wp-block-navigation a:focus {
  color: var(--wp--preset--color--accent);
}

/* active nav item border in accent */
body.theme-stellar-sextant .wp-block-navigation .current-menu-item > a {
  border-bottom: 1px solid var(--wp--preset--color--accent);
  color: var(--wp--preset--color--contrast);
}
/* /stellar-sextant precision-instrument overrides */
